import Vue from 'vue'
import Vuex from 'vuex'
// import axios from 'axios'

Vue.use(Vuex)

export default new Vuex.Store({
    state: {
        todos: [],
        isAdded: false,
        isDeleted: false,
        input: ''
    },
    getters: {
        // 过滤数据 TODO:  input的值 为空时， 数据未复原 
        searchTodoByTitle: (state) => (title) => {
            if (title.trim()) {
                return state.todos.filter(todo => todo.title.indexOf(title) !== -1)
            } else {
                // FIXME:
                window.history.go(0);
                return state.todos
            }

        },
    },
    mutations: {
        // 获取数据
        getTodos(state, payload) {
            state.todos = payload;
        },
        // 删除点击 todo
        deleteTodo(state, index) {
            state.todos.splice(index, 1);
            state.isDeleted = true;
            setTimeout(function() {
                state.isDeleted = false
            }, 3000)
        },
        // 查找数据
        searchTodo(state, title) {
            state.todos = this.getters.searchTodoByTitle(title)
        },
        // 添加todo
        addTodo(state) {
            // axios.post('/api/todos', {
            //     userId: 1,
            //     id: state.todos[state.todos.length - 1].id++,
            //     title: 'input your title of todo',
            //     completed: false
            // }).then(() => {
            //     state.isAdded = true
            // }).then(() => {
            //     setTimeout(function() {
            //         state.isAdded = false
            //     }, 3000)
            // })
            state.todos.push({
                userId: 2,
                id: state.todos[state.todos.length - 1] ? state.todos[state.todos.length - 1].id + 1 : 0,
                title: 'input your title of todo',
                completed: false
            });
            state.isAdded = true;
            setTimeout(function() {
                state.isAdded = false
            }, 3000)
        }
    },
    actions: {
        getTodos(context, payload) {
            context.commit('getTodos', payload)
        },
        addTodo(context) {
            context.commit('addTodo')
        }
    }
})